import React, { useEffect, useState } from 'react';
import api from '../api';
import moment from 'moment';

const OrderHistoryPage = () => {
  const [orders, setOrders] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');

  useEffect(() => {
    const fetchOrders = async () => {
      try {
        const res = await api.post('/orders/history/${}');
        setOrders(res.data);
      } catch (err) {
        console.error('Failed to fetch order history:', err);
        setError('Failed to load order history');
      }
      setLoading(false);
    };

    fetchOrders();
  }, []);

  return (
    <div className="container mt-5">
      <h2 className="mb-4">📜 Your Order History</h2>

      {loading && <div>Loading...</div>}
      {error && <div className="alert alert-danger">{error}</div>}

      {!loading && !error && orders.length === 0 && (
        <div className="alert alert-info">You haven’t placed any orders yet.</div>
      )}

      {!loading && orders.length > 0 && (
        <div className="accordion" id="orderHistoryAccordion">
          {orders.map((order, index) => (
            <div className="accordion-item" key={order._id}>
              <h2 className="accordion-header" id={`heading-${index}`}>
                <button
                  className="accordion-button collapsed"
                  type="button"
                  data-bs-toggle="collapse"
                  data-bs-target={`#collapse-${index}`}
                  aria-expanded="false"
                  aria-controls={`collapse-${index}`}
                >
                  🧾 Order #{order.token} - {moment(order.createdAt).format('MMMM Do YYYY, h:mm a')}
                </button>
              </h2>
              <div
                id={`collapse-${index}`}
                className="accordion-collapse collapse"
                aria-labelledby={`heading-${index}`}
                data-bs-parent="#orderHistoryAccordion"
              >
                <div className="accordion-body">
                  <ul className="list-group mb-3">
                    {order.items.map(item => (
                      <li className="list-group-item d-flex justify-content-between" key={item.food._id}>
                        <div>
                          🍽️ {item.food.name} x {item.quantity}
                        </div>
                        <div>₹{item.quantity * item.food.price}</div>
                      </li>
                    ))}
                  </ul>
                  <p><strong>Status:</strong> {order.status}</p>
                  <p><strong>Total Price:</strong> ₹{order.totalPrice}</p>
                </div>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
};

export default OrderHistoryPage;
